namespace sv_d2871fd39d8b404c97980bcf86282afe.Auth;

/// <summary>
/// Serializable user info passed from server to WebAssembly via PersistentComponentState.
/// </summary>
public sealed class UserInfo
{
    public required string Email { get; init; }
    public required string[] Roles { get; init; }
}

using System.Security.Claims;
using Microsoft.AspNetCore.Components.Authorization;

namespace sv_d2871fd39d8b404c97980bcf86282afe.Auth;

/// <summary>
/// Server-side AuthenticationStateProvider that simulates a logged-in user.
/// </summary>
public sealed class FakeAuthenticationStateProvider : AuthenticationStateProvider
{
    public override Task<AuthenticationState> GetAuthenticationStateAsync()
    {
        var claims = new List<Claim>
        {
            new(ClaimTypes.Name, "bob@example.com"),
            new(ClaimTypes.Email, "bob@example.com"),
            new(ClaimTypes.Role, "User"),
            new(ClaimTypes.Role, "Editor"),
        };

        var identity = new ClaimsIdentity(claims, authenticationType: "FakeAuth");
        var user = new ClaimsPrincipal(identity);

        return Task.FromResult(new AuthenticationState(user));
    }
}

using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;
using Microsoft.AspNetCore.Components.Web;

namespace sv_d2871fd39d8b404c97980bcf86282afe.Auth;

/// <summary>
/// Wraps the real AuthenticationStateProvider and persists user info into
/// PersistentComponentState so the WebAssembly client can restore it.
/// </summary>
public sealed class PersistingAuthenticationStateProvider : AuthenticationStateProvider, IDisposable
{
    private readonly PersistentComponentState _persistentState;
    private readonly AuthenticationStateProvider _inner;
    private PersistingComponentStateSubscription _subscription;
    private Task<AuthenticationState>? _authTask;

    public PersistingAuthenticationStateProvider(
        PersistentComponentState persistentState,
        AuthenticationStateProvider inner)
    {
        _persistentState = persistentState;
        _inner = inner;

        _subscription = _persistentState.RegisterOnPersisting(OnPersistingAsync, RenderMode.InteractiveWebAssembly);
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync()
    {
        _authTask ??= _inner.GetAuthenticationStateAsync();
        return _authTask;
    }

    private async Task OnPersistingAsync()
    {
        var authState = await GetAuthenticationStateAsync();
        var user = authState.User;

        if (user.Identity?.IsAuthenticated == true)
        {
            var userInfo = new UserInfo
            {
                Email = user.FindFirstValue(ClaimTypes.Email) ?? user.Identity.Name ?? "",
                Roles = user.FindAll(ClaimTypes.Role).Select(c => c.Value).ToArray(),
            };

            _persistentState.PersistAsJson(nameof(UserInfo), userInfo);
        }
    }

    public void Dispose()
    {
        _subscription.Dispose();
    }
}

using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;

namespace sv_d2871fd39d8b404c97980bcf86282afe.Client.Auth;

/// <summary>
/// Client-side (WebAssembly) AuthenticationStateProvider that restores user info
/// persisted by the server via PersistentComponentState.
/// </summary>
public sealed class PersistentAuthenticationStateProvider : AuthenticationStateProvider
{
    private static readonly Task<AuthenticationState> _unauthenticated =
        Task.FromResult(new AuthenticationState(new ClaimsPrincipal(new ClaimsIdentity())));

    private readonly Task<AuthenticationState> _authStateTask;

    public PersistentAuthenticationStateProvider(PersistentComponentState persistentState)
    {
        if (persistentState.TryTakeFromJson<UserInfo>(nameof(UserInfo), out var userInfo) && userInfo is not null)
        {
            var claims = new List<Claim>
            {
                new(ClaimTypes.Name, userInfo.Email),
                new(ClaimTypes.Email, userInfo.Email),
            };

            foreach (var role in userInfo.Roles)
            {
                claims.Add(new Claim(ClaimTypes.Role, role));
            }

            var identity = new ClaimsIdentity(claims, authenticationType: "FakeAuth");
            _authStateTask = Task.FromResult(new AuthenticationState(new ClaimsPrincipal(identity)));
        }
        else
        {
            _authStateTask = _unauthenticated;
        }
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync() => _authStateTask;
}

namespace sv_d2871fd39d8b404c97980bcf86282afe.Client.Auth;

/// <summary>
/// Serializable user info passed from server to WebAssembly via PersistentComponentState.
/// Must mirror the server-side UserInfo class.
/// </summary>
public sealed class UserInfo
{
    public required string Email { get; init; }
    public required string[] Roles { get; init; }
}

@page "/profile"
@rendermode InteractiveAuto
@using Microsoft.AspNetCore.Components.Authorization
@using System.Security.Claims
@inject AuthenticationStateProvider AuthStateProvider

<PageTitle>Profile</PageTitle>

<h1>Profile</h1>

@if (_user?.Identity?.IsAuthenticated == true)
{
    <p><strong>Name:</strong> @_user.Identity.Name</p>

    <h3>Roles</h3>
    <ul>
        @foreach (var role in _user.FindAll(ClaimTypes.Role))
        {
            <li>@role.Value</li>
        }
    </ul>
}
else
{
    <p>Not authenticated.</p>
}

@code {
    private ClaimsPrincipal? _user;

    protected override async Task OnInitializedAsync()
    {
        var authState = await AuthStateProvider.GetAuthenticationStateAsync();
        _user = authState.User;
    }
}

